#!/usr/bin/env node
/**
 * Extract the hat tiling's lookup tables from upstream's `puzzles/hat-tables.h`
 * into `src/native/engine/tilings/hat-tables.ts`.
 *
 *     node scripts/gen-hat-tables.mjs
 *
 * WHY A SCRIPT AND NOT A HUMAN. `hat-tables.h` is ~2,100 lines of pure array
 * data — 5,376 kitemap triples and 546 metamap pairs. Upstream does not type it
 * either: the header's own banner says it is generated by `hatgen --tables`.
 * A single mistyped digit produces a *valid-looking* tiling that diverges from
 * the C somewhere deep in the patch, so hand transcription is the one approach
 * with no cheap way to check itself (`add-aperiodic-tilings` design D3).
 *
 * The header is plain C initialisers with no macros, so a regex over each
 * located table span is enough; the emitted file carries the element counts and
 * sentinel counts as a header comment, and `hat.test.ts` re-asserts them against
 * the figures the C survey recorded independently.
 */

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const SRC = resolve(root, "puzzles/hat-tables.h");
const OUT = resolve(root, "src/native/engine/tilings/hat-tables.ts");

const source = readFileSync(SRC, "utf8");

/** The body text of `static const <anything> <name>[] = { … };`. */
function tableBody(name) {
  const re = new RegExp(`static const [^;]*?\\b${name}\\[\\]\\s*=\\s*\\{`, "s");
  const m = re.exec(source);
  if (!m) throw new Error(`gen-hat-tables: table ${name} not found`);
  // Scan for the brace that closes the initialiser rather than looking for a
  // fixed "\n};": one-liners like `hats_in_metatile` close on the same line,
  // and entry braces nest one level deep inside every other table.
  const start = m.index + m[0].length;
  let depth = 1;
  for (let i = start; i < source.length; i++) {
    if (source[i] === "{") depth++;
    else if (source[i] === "}" && --depth === 0) return source.slice(start, i);
  }
  throw new Error(`gen-hat-tables: unterminated table ${name}`);
}

/** Strip C comments — every table interleaves them with its data. */
const uncomment = (s) => s.replace(/\/\*[\s\S]*?\*\//g, "");

/** Flatten `{a,b,…}` brace groups into one number list, `n` values per group. */
function braceGroups(body, n, name) {
  const groups = [...uncomment(body).matchAll(/\{([^}]*)\}/g)].map((m) =>
    m[1]
      .split(",")
      .map((t) => t.trim())
      .filter((t) => t.length > 0)
      .map((t) => {
        const v = Number(t);
        if (!Number.isInteger(v)) {
          throw new Error(`gen-hat-tables: ${name} has non-integer "${t}"`);
        }
        return v;
      }),
  );
  for (const g of groups) {
    if (g.length !== n) {
      throw new Error(
        `gen-hat-tables: ${name} entry has ${g.length} fields, expected ${n}`,
      );
    }
  }
  return groups;
}

/** A bare comma-separated list of numbers, e.g. `nchildren`. */
function numberList(body, name) {
  return uncomment(body)
    .split(",")
    .map((t) => t.trim())
    .filter((t) => t.length > 0)
    .map((t) => {
      const v = Number(t);
      if (!Number.isInteger(v)) {
        throw new Error(`gen-hat-tables: ${name} has non-integer "${t}"`);
      }
      return v;
    });
}

/** A list of `TT_*` enum names mapped to their ordinals. */
const TILE_TYPES = ["TT_H", "TT_T", "TT_P", "TT_F"];
function tileTypeList(body, name) {
  return uncomment(body)
    .split(",")
    .map((t) => t.trim())
    .filter((t) => t.length > 0)
    .map((t) => {
      const i = TILE_TYPES.indexOf(t);
      if (i < 0) throw new Error(`gen-hat-tables: ${name} has unknown "${t}"`);
      return i;
    });
}

const LETTERS = ["H", "T", "P", "F"];

const hatsInMetatile = numberList(tableBody("hats_in_metatile"), "hats_in_metatile");
const nchildren = numberList(tableBody("nchildren"), "nchildren");
const children = LETTERS.map((L) =>
  tileTypeList(tableBody(`children_${L}`), `children_${L}`),
);
const kitemaps = LETTERS.map((L) =>
  braceGroups(tableBody(`kitemap_${L}`), 3, `kitemap_${L}`),
);
const metamaps = LETTERS.map((L) =>
  braceGroups(tableBody(`metamap_${L}`), 2, `metamap_${L}`),
);

// --- Sanity checks the survey pinned down independently -------------------
// These are structural invariants of the tiling, not of the file format, so a
// formatting drift that silently dropped entries fails here rather than
// producing a short table that only misbehaves at runtime.
const expect = (got, want, what) => {
  if (got !== want) throw new Error(`gen-hat-tables: ${what}: ${got} != ${want}`);
};
for (let i = 0; i < 4; i++) {
  expect(children[i].length, nchildren[i], `children_${LETTERS[i]} length`);
  // kitemap is indexed step + 4*(kite + 8*(hat + 4*meta)) => 4*8*4*nchildren.
  expect(kitemaps[i].length, 128 * nchildren[i], `kitemap_${LETTERS[i]} length`);
  // metamap is indexed meta2*13 + meta, over meta2 < nchildren.
  expect(metamaps[i].length, 13 * nchildren[i], `metamap_${LETTERS[i]} length`);
}

const kiteSentinels = kitemaps.map(
  (t) => t.filter((e) => e[0] === -1 && e[1] === -1 && e[2] === -1).length,
);
const metaSentinels = metamaps.map((t) => t.filter((e) => e[0] === -1).length);

for (const [name, table] of [
  ["kitemap", kitemaps],
  ["metamap", metamaps],
]) {
  for (const entries of table) {
    for (const e of entries) {
      for (const v of e) {
        if (v < -1 || v > 12) {
          throw new Error(`gen-hat-tables: ${name} value ${v} outside [-1,12]`);
        }
      }
    }
  }
}

// --- Emit ------------------------------------------------------------------

const flat = (groups) => groups.flat();
const int8 = (name, values) =>
  `export const ${name} = /* @__PURE__ */ new Int8Array([\n${wrap(values)}\n]);\n`;

function wrap(values) {
  const lines = [];
  for (let i = 0; i < values.length; i += 24) {
    lines.push(`  ${values.slice(i, i + 24).join(", ")},`);
  }
  return lines.join("\n");
}

const banner = `/**
 * Hat tiling lookup tables — GENERATED FILE, DO NOT EDIT BY HAND.
 *
 * Extracted from upstream \`puzzles/hat-tables.h\` by \`scripts/gen-hat-tables.mjs\`;
 * that header is itself generated by upstream's \`auxiliary/hatgen.c\`
 * (\`hatgen --tables\`). Regenerate with:
 *
 *     node scripts/gen-hat-tables.mjs
 *
 * The kitemaps and metamaps are stored **flat**, in \`Int8Array\`s indexed by
 * upstream's own arithmetic (\`kitemapIndex\` / \`metamapIndex\` in \`hat.ts\`), with
 * each logical entry's fields adjacent: a kitemap entry is 3 consecutive values
 * (kite, hat, meta) and a metamap entry is 2 (meta, meta2). Every value lies in
 * [-1, 12], and \`-1\` is the "impossible" sentinel. Flat typed arrays rather than
 * objects because the kitemaps alone would otherwise be 5,376 allocations.
 *
 * Extraction counts (re-asserted in \`hat.test.ts\`):
${LETTERS.map(
  (L, i) =>
    ` *   kitemap_${L}: ${kitemaps[i].length} entries, ${kiteSentinels[i]} impossible;` +
    ` metamap_${L}: ${metamaps[i].length} entries, ${metaSentinels[i]} sentinel`,
).join("\n")}
 */
`;

const out = `${banner}
/** Metatile types, in upstream's \`TileType\` ordinal order. Used as indices. */
export const TT_H = 0;
export const TT_T = 1;
export const TT_P = 2;
export const TT_F = 3;

/** \`tilechars\` — the desc letter for each metatile type, by ordinal. */
export const TILE_CHARS = "HTPF";

/** Number of hats belonging to each metatile type. */
export const hatsInMetatile = /* @__PURE__ */ new Int8Array([${hatsInMetatile.join(", ")}]);

/** Number of child metatiles in each metatile type's expansion. */
export const nchildren = /* @__PURE__ */ new Int8Array([${nchildren.join(", ")}]);

/** \`children[type][i]\` — the type of the i'th child of a metatile. */
export const children: readonly Int8Array[] = /* @__PURE__ */ [
${children.map((c) => `  new Int8Array([${c.join(", ")}]),`).join("\n")}
];

${LETTERS.map((L, i) => int8(`kitemap${L}`, flat(kitemaps[i]))).join("\n")}
/** \`kitemap[meta2type]\`, flat; see \`kitemapIndex\`. Stride 3 per entry. */
export const kitemap: readonly Int8Array[] = [kitemapH, kitemapT, kitemapP, kitemapF];

${LETTERS.map((L, i) => int8(`metamap${L}`, flat(metamaps[i]))).join("\n")}
/** \`metamap[meta3type]\`, flat; see \`metamapIndex\`. Stride 2 per entry. */
export const metamap: readonly Int8Array[] = [metamapH, metamapT, metamapP, metamapF];
`;

writeFileSync(OUT, out);
console.log(`wrote ${OUT}`);
console.log(
  `kitemap entries ${kitemaps.map((t) => t.length).join("/")}` +
    ` (impossible ${kiteSentinels.join("/")}, total ${kiteSentinels.reduce((a, b) => a + b, 0)})`,
);
console.log(
  `metamap entries ${metamaps.map((t) => t.length).join("/")}` +
    ` (sentinel ${metaSentinels.join("/")}, total ${metaSentinels.reduce((a, b) => a + b, 0)})`,
);
